import pandas as pd
import numpy as np


def make_frame(n, start=0):
    return pd.DataFrame({
        'id': range(start, start + n),
        'value': np.random.rand(n),
    })


def combine_frames(df1, df2):
    # BUG: DataFrame.append removed in pandas 2.0
    return df1.append(df2, ignore_index=True)


def main():
    a = make_frame(5, 0)
    b = make_frame(5, 5)
    combined = combine_frames(a, b)
    print(combined.shape)


if __name__ == '__main__':
    main()
